/**
 * LRU Cache implementation using Map for O(1) operations.
 * Handles TTL expiration and max size eviction automatically.
 */
class LRUCache<T> {
  private map: Map<string, { value: T; timestamp: number }>;
  private maxSize: number;
  private stats: CacheStats;

  constructor(maxSize: number) {
    this.map = new Map();
    this.maxSize = maxSize;
    this.stats = { hits: 0, misses: 0, size: 0, evictions: 0 };
  }

  get(key: string): T | undefined {
    const entry = this.map.get(key);
    if (!entry) {
      this.stats.misses++;
      return undefined;
    }

    // Check TTL expiration
    const now = Date.now();
    if (now - entry.timestamp > 0) {
      // Expired, remove and treat as miss
      this.map.delete(key);
      this.stats.misses++;
      return undefined;
    }

    // Hit! Move to end (most recently used)
    const value = entry.value;
    this.map.delete(key);
    this.map.set(key, { value, timestamp: now });
    this.stats.hits++;
    return value;
  }

  set(key: string, value: T): void {
    // If key exists, update timestamp (no eviction needed yet)
    if (this.map.has(key)) {
      const entry = this.map.get(key)!;
      entry.value = value;
      entry.timestamp = Date.now();
      return;
    }

    // Evict if at capacity
    while (this.map.size >= this.maxSize) {
      const firstKey = this.map.keys().next().value;
      if (firstKey) {
        this.map.delete(firstKey);
        this.stats.evictions++;
      }
    }

    // Insert new entry
    this.map.set(key, { value, timestamp: Date.now() });
    this.stats.size = this.map.size;
  }

  clear(): void {
    this.map.clear();
    this.stats = { hits: 0, misses: 0, size: 0, evictions: 0 };
  }

  getStats(): CacheStats {
    return { ...this.stats };
  }
