  private readonly maxSize: number;
  private hits: number = 0;
  private misses: number = 0;
  private evictions: number = 0;

  constructor(baseUrl: string, options: CacheOptions) {
    super(baseUrl);
    this.ttl = options.ttl;
    this.maxSize = options.maxSize;
  }

  private getCacheKey(path: string): string {
    return path;
  }

  private isExpired(item: LRUCacheItem<any>): boolean {
    return Date.now() - item.timestamp > this.ttl;
  }

  private evictOldest(): void {
    if (this.cache.size === 0) return;

    const oldestKey = this.cache.keys().next().value;
    if (oldestKey) {
      this.cache.delete(oldestKey);
      this.evictions++;
    }
  }

  private cleanupExpired(): void {
    for (const [key, item] of this.cache.entries()) {
      if (this.isExpired(item)) {
        this.cache.delete(key);
      }
    }
  }

  private ensureCapacity(): void {
    while (this.cache.size >= this.maxSize) {
      this.evictOldest();
    }
  }

  async fetch<T>(path: string): Promise<T> {
    const key = this.getCacheKey(path);
    const cachedItem = this.cache.get(key);

    if (cachedItem && !this.isExpired(cachedItem)) {
      this.hits++;
      return cachedItem.data;
    }

    this.misses++;
    const result = await super.fetch<T>(path);

    if (this.cache.size >= this.maxSize) {
      this.evictOldest();
    }

    this.cache.set(key, { data: result, timestamp: Date.now() });
    return result;
  }

  invalidate(pattern: string | RegExp): number {
    let count = 0;
    const keysToDelete: string[] = [];

    for (const key of this.cache.keys()) {
      if (typeof pattern === 'string') {
        if (key.includes(pattern)) {
          keysToDelete.push(key);
        }
      } else if (pattern.test(key)) {
        keysToDelete.push(key);
      }
    }

    for (const key of keysToDelete) {
      this.cache.delete(key);
      count++;
    }

    return count;
  }

  clear(): void {
    this.cache.clear();
    this.hits = 0;
    this.misses = 0;
    this.evictions = 0;
  }

  getStats(): CacheStats {
    this.cleanupExpired();
    return {
      hits: this.hits,
      misses: this.misses,
      size: this.cache.size,
      evictions: this.evictions,
