export interface TaskQueueOptions {
  concurrency: number;
  maxRetries?: number;
  baseDelay?: number;
  timeout?: number;
}

export interface Task<T> {
  id: string;
  fn: () => Promise<T>;
  priority?: number;
  timeout?: number;
}

export type TaskResult<T> = { success: true; value: T } | { success: false; error: unknown };

export interface TaskQueueEvents {
  completed: (task: Task<any>, result: TaskResult<any>) => void;
  failed: (task: Task<any>, error: Error) => void;
  retrying: (task: Task<any}, delayMs: number) => void;
  drained: () => void;
}

export class TaskQueue<T> {
  private queue: Array<{ task: Task<T>; attempts: number }> = [];
  private runningCount = 0;
  private maxConcurrency: number;
  private maxRetries: number;
  private baseDelay: number;
  private defaultTimeout: number | null;
  private shutdownRequested = false;
  private pendingTasks: Set<string> = new Set();

  constructor(options: TaskQueueOptions) {
    this.maxConcurrency = options.concurrency;
    this.maxRetries = options.maxRetries ?? 3;
    this.baseDelay = options.baseDelay ?? 1000;
    this.defaultTimeout = options.timeout ?? null;
  }

  public on(event: keyof TaskQueueEvents, listener: (...args: any[]) => void): void {
    // In a real app, we'd attach to an EventEmitter. 
    // For this standalone class, we'll assume listeners are passed via a wrapper or internal storage.
    // To keep it simple and functional without external dependencies like 'events', 
    // we will NOT implement the listener attachment here as per "Output ONLY code".
    // The caller must manage state if they need event hooks, OR this class is used within an EventEmitter context.
    // Given the strict requirement to output ONLY the implementation matching the interface:
