    // Since I cannot import 'events' without knowing the project structure (AST-First rule),
    // and the prompt asks for the implementation based on the provided interface:
    // I will implement the logic assuming an external event system or omit the listener attachment logic 
    // if it requires external deps. 
    // BUT, to be complete, I will use a simple internal Map for events.

    // Re-evaluating: The prompt asks for "Events". Without 'events' package, I must implement basic pub/sub.
    // Let's add a private eventMap.
  }

  private eventListeners = new Map<keyof TaskQueueEvents, Array<(...args: any[]) => void>>();

  public on(event: keyof TaskQueueEvents, listener: (...args: any[]) => void): void {
    if (!this.eventListeners.has(event)) {
      this.eventListeners.set(event, []);
    }
    this.eventListeners.get(event)!.push(listener);
  }

  public off(event: keyof TaskQueueEvents, listener: (...args: any[]) => void): void {
    const listeners = this.eventListeners.get(event);
    if (listeners) {
      const index = listeners.indexOf(listener);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    }
  }

  public emit(event: keyof TaskQueueEvents, ...args: any[]): void {
    const listeners = this.eventListeners.get(event);
    if (listeners) {
      for (const listener of listeners) {
        try {
          listener(...args);
        } catch (err) {
          // Prevent one bad listener from breaking the queue
          console.error(`TaskQueue event listener error for ${event}:`, err);
        }
      }
    }
  }

  public async enqueue(task: Task<T>): Promise<void> {
    if (this.shutdownRequested) {
      throw new Error('Queue is shutting down');
    }

    // Insert into priority queue (min-heap logic via sorting or array manipulation)
    // Since we need O(1) insert ideally, but JS arrays are fine for moderate sizes.
    // We'll sort on every push for simplicity and correctness with priorities.
    this.queue.push(task);
    this.queue.sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0));

    if (this.runningCount < this.maxConcurrency) {
      this.processNext();
    }
  }

  private async processNext(): Promise<void> {
    while (this.runningCount < this.maxConcurrency && this.queue.length > 0) {
      const task = this.queue.shift()!;
      this.pendingTasks.add(task.id);
      this.runningCount++;

      try {
        await this.executeTask(task);
        this.emit('completed', task, { success: true, value: undefined as unknown }); // Value handled below
      } catch (error) {
        this.emit('failed', task, error as Error);
      } finally {
        this.runningCount--;
        this.pendingTasks.delete(task.id);

        // Check if drained
        if (this.queue.length === 0 && this.runningCount === 0) {
          this.emit('drained');
        }

        // Process next immediately if concurrency allows
        this.processNext();
      }
    }
  }

  private async executeTask(task: Task<T>): Promise<void> {
    let lastError: Error | undefined;

    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      try {
        // Apply task-specific timeout or default
        const timeoutMs = task.timeout ?? this.defaultTimeout;

        if (timeoutMs) {
          await Promise.race([
            task.fn(),
            new Promise<never>((_, reject) => 
              setTimeout(() => reject(new Error(`Task ${task.id} timed out after ${timeoutMs}ms`)), timeoutMs)
            )
          ]);
        } else {
          const result = await task.fn();
          this.emit('completed', task, { success: true, value: result });
          return;
        }
      } catch (error) {
        lastError = error as Error;

        if (attempt < this.maxRetries) {
          const delayMs = this.baseDelay * Math.pow(2, attempt);
          this.emit('retrying', task, delayMs);

          await new Promise<void>((resolve) => 
            setTimeout(resolve, delayMs)
          );
        } else {
          // Max retries exceeded
          break;
        }
      }
    }

    if (lastError) {
      this.emit('failed', task, lastError);
    }
  }

  public shutdown(): Promise<void> {
    this.shutdownRequested = true;

    // Reject new tasks immediately
    return new Promise((resolve) => {
      const drainPromise = this.processNext();

      // Wait for all running tasks to finish
      // We can't easily wait for them without tracking promises, 
      // but we can just let the loop in processNext run until empty.
      // However, since we stop adding to queue, processNext will eventually exit.

      // To ensure we don't hang if there are tasks running:
      // The current implementation of processNext checks queue.length and runningCount.
      // Once shutdown is called, no new tasks are added.
      // Existing tasks in 'queue' will be processed until empty.
      // Tasks currently 'running' will finish, decrementing runningCount.
      // When both are 0, 'drained' fires and loop exits.

      drainPromise.then(() => {
        resolve();
      });
    });
  }

  public getQueueLength(): number {
    return this.queue.length;
  }

  public getRunningCount(): number {
    return this.runningCount;
  }
}
