```typescript
type StateValue<T> = string | T;
type EventName = string;
type Context = Record<string, unknown>;

interface GuardFn<C extends Context> {
  (ctx: C): boolean;
}

interface ActionFn<C extends Context> {
  (ctx: C): Partial<C> | void;
}

interface StateConfig<S extends StateValue<any>, E extends EventName, C extends Context> {
  on?: Record<E, TransitionConfig<S, E, C>>;
  entry?: ActionFn<C>;
  exit?: ActionFn<C>;
  states?: Record<string, StateConfig<any, any, C>>;
}

interface TransitionConfig<S extends StateValue<any>, E extends EventName, C extends Context> {
  target: S;
  guard?: GuardFn<C>;
  action?: ActionFn<C>;
}

interface MachineState<S extends StateValue<any>, C extends Context> {
  value: S;
  context: C;
  history: S[];
}

export class StateMachine<
  S extends StateValue<any>,
  E extends EventName,
  C extends Context
> {
  private initial: S;
  private states: Record<string, StateConfig<S, E, C>>;
  private listeners: Set<(state: MachineState<S, C>) => void>;

  private currentContext: C;
  private currentState: S;
  private history: S[];

  constructor(config: {
    initial: S;
    context: C;
    states: Record<string, StateConfig<S, E, C>>;
  }) {
    this.initial = config.initial;
    this.states = config.states;
    this.listeners = new Set();

    // Initialize state
    this.currentState = config.initial as S;
    this.currentContext = { ...config.context };
    this.history = [];

    // Trigger entry action for initial state if defined
    const initialStateConfig = this.states[config.initial];
    if (initialStateConfig?.entry) {
      this.currentContext = { ...this.currentContext, ...(initialStateConfig.entry(this.currentContext)) } as C;
    }
  }

  public get state(): S {
    return this.currentState;
  }

  public get context(): Readonly<C> {
    return this.currentContext;
  }

  public on(event: (state: MachineState<S, C>) => void): void {
    this.listeners.add(event);
  }

  public send(eventName: E): boolean {
    const transition = this.states[this.currentState]?.on?.[eventName];

    if (!transition) return false;

    // Execute guard if present
    if (transition.guard && !transition.guard(this.currentContext)) {
      return false;
    }

    // Execute action before transition
    if (transition.action) {
      this.currentContext = { ...this.currentContext, ...(transition.action(this.currentContext)) } as C;
    }

    // Handle hierarchical states
    const targetStateName = typeof transition.target === 'string' ? transition.target : this.currentState;

    // If target is a state object (hierarchical), we need to resolve it
    let targetValue: S = targetStateName;

    if (this.states[targetStateName]) {
      // It's a nested state machine or just a named state in the same hierarchy
      // For simplicity in this implementation, we treat string targets as direct state names
      // If you need deep nesting, you would need to resolve the path here.
      targetValue = targetStateName;
    }

    // Update history
    this.history.push(this.currentState);

    // Update current state
    this.currentState = targetValue;

    // Execute exit action for old state
    const oldStateConfig = this.states[this.history[this.history.length - 2]];
    if (oldStateConfig?.exit) {
      this.currentContext = { ...this.currentContext, ...(oldStateConfig.exit(this.currentContext)) } as C;
    }

    // Execute entry action for new state
    const newStateConfig = this.states[targetValue];
    if (newStateConfig?.entry) {
      this.currentContext = { ...this.currentContext, ...(newStateConfig.entry(this.currentContext)) } as C;
    }

    // Notify listeners
    this.listeners.forEach(listener => listener({ value: this.currentState, context: this.currentContext }));

    return true;
  }

  public toJSON(): { state: S; context: C; history: S[] } {
    return {
      state: this.currentState,
      context: this.currentContext,
      history: [...this.history],
    };
  }

  public fromJSON(data: { state: S; context: C; history?: S[] }): void {
    this.currentState = data.state;
    this.currentContext = data.context;
    if (data.history) {
      this.history = data.history;
    } else {
      // Reconstruct history based on current state
      const currentStateConfig = this.states[this.currentState];
      if (currentStateConfig?.exit) {
        // We can't perfectly reconstruct history without knowing the full transition graph,
        // so we leave it as is or clear it.
        this.history = [];
      }
    }
  }

  public getState(): MachineState<S, C> {
    return {
      value: this.currentState,
      context: this.currentContext,
      history: [...this.history],
    };
  }
}
